'use client';

import { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import {
  LayoutDashboard,
  Wallet,
  CheckCircle,
  History,
  Shield,
  BarChart3,
  Users,
  HelpCircle,
  Settings,
  LogOut,
  ChevronLeft,
  ChevronRight,
  Menu,
  X,
  User,
} from 'lucide-react';
import { useAuth } from '@/lib/auth-context';
import Link from 'next/link';

interface SidebarProps {
  onNavigate: (path: string) => void;
  currentSection: string;
  onCollapseChange?: (collapsed: boolean) => void;
}

// Logo Component
const ClawLogo = ({ className = "w-7 h-7" }: { className?: string }) => (
  <svg className={className} viewBox="0 0 120 120" fill="none">
    <rect width="120" height="120" rx="28" fill="#FF4D2E"/>
    <path d="M35 45C35 45 25 55 25 70C25 85 35 95 45 90C50 87 52 80 50 75C48 70 42 68 40 72C38 76 42 78 45 76" 
          stroke="white" strokeWidth="5" strokeLinecap="round" strokeLinejoin="round" fill="none"/>
    <path d="M85 45C85 45 95 55 95 70C95 85 85 95 75 90C70 87 68 80 70 75C72 70 78 68 80 72C82 76 78 78 75 76" 
          stroke="white" strokeWidth="5" strokeLinecap="round" strokeLinejoin="round" fill="none"/>
    <ellipse cx="60" cy="70" rx="12" ry="18" fill="white"/>
    <path d="M55 55C55 50 58 45 60 42C62 45 65 50 65 55" 
          stroke="white" strokeWidth="4" strokeLinecap="round" fill="none"/>
    <circle cx="48" cy="65" r="3" fill="#FF4D2E"/>
    <circle cx="72" cy="65" r="3" fill="#FF4D2E"/>
    <circle cx="60" cy="75" r="4" fill="#FF4D2E"/>
  </svg>
);

const menuItems = [
  { id: 'dashboard', label: '仪表盘', icon: LayoutDashboard },
  { id: 'wallets', label: '钱包管理', icon: Wallet },
  { id: 'approvals', label: '交易审批', icon: CheckCircle },
  { id: 'transactions', label: '交易记录', icon: History },
  { id: 'risk', label: '风控安全', icon: Shield },
  { id: 'analytics', label: '数据分析', icon: BarChart3 },
  { id: 'contacts', label: '地址簿', icon: Users },
  { id: 'help', label: '帮助中心', icon: HelpCircle },
  { id: 'settings', label: '系统设置', icon: Settings },
];

export default function Sidebar({ onNavigate, currentSection, onCollapseChange }: SidebarProps) {
  const [collapsed, setCollapsed] = useState(false);
  const [mobileOpen, setMobileOpen] = useState(false);
  const [isMobile, setIsMobile] = useState(false);
  const { user, logout } = useAuth();

  useEffect(() => {
    const checkMobile = () => {
      setIsMobile(window.innerWidth < 1024);
      if (window.innerWidth < 1024) {
        setCollapsed(true);
      }
    };
    
    checkMobile();
    window.addEventListener('resize', checkMobile);
    return () => window.removeEventListener('resize', checkMobile);
  }, []);

  const handleCollapse = () => {
    const newCollapsed = !collapsed;
    setCollapsed(newCollapsed);
    onCollapseChange?.(newCollapsed);
  };

  const handleNavigate = (section: string) => {
    onNavigate(section);
    if (isMobile) {
      setMobileOpen(false);
    }
  };

  const handleLogout = () => {
    logout();
    window.location.href = '/login';
  };

  if (isMobile) {
    return (
      <>
        {/* Mobile Header */}
        <div className="fixed top-0 left-0 right-0 h-16 bg-white/95 backdrop-blur-xl border-b border-gray-200 z-50 flex items-center justify-between px-4">
          <Link href="/" className="flex items-center gap-3 no-underline">
            <ClawLogo className="w-8 h-8" />
            <div>
              <h1 className="text-base font-bold text-gray-900">Claw Wallet</h1>
              <p className="text-xs text-gray-500">OpenClaw 原生加密钱包</p>
            </div>
          </Link>
          <button
            onClick={() => setMobileOpen(true)}
            className="p-2 rounded-lg bg-gray-100 text-gray-500 hover:text-gray-900 hover:bg-gray-200 transition-colors"
          >
            <Menu className="h-6 w-6" />
          </button>
        </div>

        <AnimatePresence>
          {mobileOpen && (
            <>
              <motion.div
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                exit={{ opacity: 0 }}
                onClick={() => setMobileOpen(false)}
                className="fixed inset-0 bg-black/80 backdrop-blur-sm z-50"
              />
              <motion.aside
                initial={{ x: '-100%' }}
                animate={{ x: 0 }}
                exit={{ x: '-100%' }}
                transition={{ type: 'spring', damping: 25, stiffness: 200 }}
                className="fixed left-0 top-0 h-full w-72 bg-white border-r border-gray-200 z-50 flex flex-col"
              >
                {/* Mobile Sidebar Header */}
                <div className="h-16 flex items-center justify-between px-4 border-b border-gray-200">
                  <Link href="/" className="flex items-center gap-3 no-underline">
                    <ClawLogo className="w-8 h-8" />
                    <div>
                      <h1 className="text-base font-bold text-gray-900">Claw Wallet</h1>
                      <p className="text-xs text-gray-500">OpenClaw 原生加密钱包</p>
                    </div>
                  </Link>
                  <button
                    onClick={() => setMobileOpen(false)}
                    className="p-2 rounded-lg bg-gray-100 text-gray-500 hover:text-gray-900 hover:bg-gray-200 transition-colors"
                  >
                    <X className="h-5 w-5" />
                  </button>
                </div>

                {user && (
                  <div className="p-4 border-b border-gray-200">
                    <div className="flex items-center gap-3">
                      <div className="w-12 h-12 rounded-full bg-[#FF4D2E] flex items-center justify-center">
                        {user.avatar ? (
                          <img src={user.avatar} alt={user.name} className="w-full h-full rounded-full" />
                        ) : (
                          <User className="h-6 w-6 text-white" />
                        )}
                      </div>
                      <div className="flex-1 min-w-0">
                        <p className="text-gray-900 font-medium truncate">{user.name}</p>
                        <p className="text-gray-500 text-sm truncate">{user.email}</p>
                      </div>
                    </div>
                  </div>
                )}

                <nav className="flex-1 py-4 px-3 space-y-1 overflow-y-auto">
                  {menuItems.map((item) => {
                    const isActive = currentSection === item.id;
                    const Icon = item.icon;
                    
                    return (
                      <button
                        key={item.id}
                        onClick={() => handleNavigate(item.id)}
                        className={`w-full flex items-center gap-3 px-3 py-3 rounded-xl transition-all ${
                          isActive
                            ? 'bg-[#FF4D2E]/10 text-gray-900 border border-[#FF4D2E]/30'
                            : 'text-gray-500 hover:bg-gray-100 hover:text-gray-900'
                        }`}
                      >
                        <Icon className={`h-5 w-5 flex-shrink-0 ${isActive ? 'text-[#FF4D2E]' : ''}`} />
                        <span className="font-medium">{item.label}</span>
                        {isActive && (
                          <div className="ml-auto w-1.5 h-1.5 rounded-full bg-[#FF4D2E]" />
                        )}
                      </button>
                    );
                  })}
                </nav>

                <div className="p-3 border-t border-gray-200 space-y-1">
                  <button
                    onClick={() => handleNavigate('settings')}
                    className={`w-full flex items-center gap-3 px-3 py-3 rounded-xl transition-all ${
                      currentSection === 'settings'
                        ? 'bg-[#FF4D2E]/10 text-gray-900'
                        : 'text-gray-500 hover:bg-gray-100 hover:text-gray-900'
                    }`}
                  >
                    <Settings className="h-5 w-5 flex-shrink-0" />
                    <span className="font-medium">设置</span>
                  </button>
                  <button
                    onClick={handleLogout}
                    className="w-full flex items-center gap-3 px-3 py-3 rounded-xl text-red-400 hover:bg-red-500/10 transition-colors"
                  >
                    <LogOut className="h-5 w-5 flex-shrink-0" />
                    <span className="font-medium">退出登录</span>
                  </button>
                </div>
              </motion.aside>
            </>
          )}
        </AnimatePresence>

        {/* Mobile Bottom Nav */}
        <div className="fixed bottom-0 left-0 right-0 h-16 bg-white/95 backdrop-blur-xl border-t border-gray-200 z-40 flex items-center justify-around px-2">
          {menuItems.slice(0, 5).map((item) => {
            const isActive = currentSection === item.id;
            const Icon = item.icon;
            
            return (
              <button
                key={item.id}
                onClick={() => handleNavigate(item.id)}
                className={`flex flex-col items-center justify-center gap-1 py-2 px-3 rounded-lg transition-colors ${
                  isActive ? 'text-[#FF4D2E]' : 'text-gray-500'
                }`}
              >
                <Icon className="h-5 w-5" />
                <span className="text-xs">{item.label.slice(0, 2)}</span>
              </button>
            );
          })}
          <button
            onClick={() => setMobileOpen(true)}
            className="flex flex-col items-center justify-center gap-1 py-2 px-3 rounded-lg text-gray-500"
          >
            <Menu className="h-5 w-5" />
            <span className="text-xs">更多</span>
          </button>
        </div>
      </>
    );
  }

  return (
    <motion.aside
      initial={false}
      animate={{ width: collapsed ? 80 : 260 }}
      className="fixed left-0 top-0 h-screen bg-white border-r border-gray-200 z-50 flex flex-col"
    >
      {/* Sidebar Header */}
      <div className="h-16 flex items-center justify-between px-4 border-b border-gray-200">
        <Link href="/" className="flex items-center gap-3 overflow-hidden no-underline">
          <ClawLogo className="w-8 h-8 flex-shrink-0" />
          {!collapsed && (
            <motion.div
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
            >
              <h1 className="text-base font-bold text-gray-900 whitespace-nowrap">Claw Wallet</h1>
              <p className="text-xs text-gray-500 whitespace-nowrap">OpenClaw 原生加密钱包</p>
            </motion.div>
          )}
        </Link>
        <motion.button
          onClick={handleCollapse}
          className="p-1.5 rounded-lg bg-gray-100 text-gray-500 hover:text-gray-900 hover:bg-gray-200 transition-colors"
          whileHover={{ scale: 1.05 }}
          whileTap={{ scale: 0.95 }}
        >
          {collapsed ? <ChevronRight className="h-4 w-4" /> : <ChevronLeft className="h-4 w-4" />}
        </motion.button>
      </div>

      {!collapsed && user && (
        <div className="p-4 border-b border-gray-200">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-full bg-[#FF4D2E] flex items-center justify-center flex-shrink-0">
              {user.avatar ? (
                <img src={user.avatar} alt={user.name} className="w-full h-full rounded-full" />
              ) : (
                <User className="h-5 w-5 text-white" />
              )}
            </div>
            <div className="flex-1 min-w-0">
              <p className="text-gray-900 font-medium text-sm truncate">{user.name}</p>
              <p className="text-gray-500 text-xs truncate">{user.email}</p>
            </div>
          </div>
        </div>
      )}

      <nav className="flex-1 py-4 px-3 space-y-1 overflow-y-auto">
        {menuItems.map((item) => {
          const isActive = currentSection === item.id;
          const Icon = item.icon;
          
          return (
            <motion.button
              key={item.id}
              onClick={() => handleNavigate(item.id)}
              className={`w-full flex items-center gap-3 px-3 py-3 rounded-xl transition-all duration-200 ${
                isActive
                  ? 'bg-[#FF4D2E]/10 text-gray-900 border border-[#FF4D2E]/30'
                  : 'text-gray-500 hover:bg-gray-100 hover:text-gray-900'
              }`}
              whileHover={{ scale: 1.02, x: 2 }}
              whileTap={{ scale: 0.98 }}
              title={collapsed ? item.label : undefined}
            >
              <Icon className={`h-5 w-5 flex-shrink-0 ${isActive ? 'text-[#FF4D2E]' : ''}`} />
              {!collapsed && (
                <motion.span
                  initial={{ opacity: 0 }}
                  animate={{ opacity: 1 }}
                  className="font-medium whitespace-nowrap"
                >
                  {item.label}
                </motion.span>
              )}
              {isActive && !collapsed && (
                <motion.div
                  layoutId="activeIndicator"
                  className="ml-auto w-1.5 h-1.5 rounded-full bg-[#FF4D2E]"
                />
              )}
            </motion.button>
          );
        })}
      </nav>

      <div className="p-3 border-t border-gray-200 space-y-1">
        <motion.button
          onClick={handleLogout}
          className="w-full flex items-center gap-3 px-3 py-3 rounded-xl text-red-400 hover:bg-red-500/10 transition-colors"
          whileHover={{ scale: 1.02 }}
          whileTap={{ scale: 0.98 }}
          title={collapsed ? '退出登录' : undefined}
        >
          <LogOut className="h-5 w-5 flex-shrink-0" />
          {!collapsed && <span className="font-medium whitespace-nowrap">退出登录</span>}
        </motion.button>
      </div>
    </motion.aside>
  );
}
